using System;
using System.Reflection;
using System.Linq;

var v3dll = "/home/runner/.nuget/packages/mstest.testframework/3.8.0/lib/net8.0/Microsoft.VisualStudio.TestPlatform.TestFramework.dll";
var v4dll = "/home/runner/.nuget/packages/mstest.testframework/4.2.1/lib/net8.0/MSTest.TestFramework.dll";

foreach (var (ver, path) in new[] { ("v3", v3dll), ("v4", v4dll) })
{
    Console.WriteLine($"=== {ver} ===");
    var asm = Assembly.LoadFrom(path);
    var assertType = asm.GetTypes().FirstOrDefault(t => t.Name == "Assert" && !t.Name.Contains("Handler"));
    if (assertType == null) { Console.WriteLine("Assert type not found"); continue; }

    var methods = assertType.GetMethods(BindingFlags.Public | BindingFlags.Static)
        .Where(m => m.Name.Contains("AreEqual") || m.Name.Contains("AreNotEqual") || m.Name.Contains("AreSame") || m.Name.Contains("AreNotSame"))
        .OrderBy(m => m.Name);

    foreach (var m in methods)
    {
        var genArgs = m.IsGenericMethod ? $"<{string.Join(",", m.GetGenericArguments().Select(a => a.Name))}>" : "";
        var ps = string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
        Console.WriteLine($"  {m.Name}{genArgs}({ps})");
    }
    Console.WriteLine();
}
EOF
